def countDistinctSubsequences(s: str) -> int:
    n = len(s)

    dp = [0] * (n + 1)
    dp[0] = 1

    last_occurrence = {} 

    for i in range(1, n + 1):
        current_char = s[i - 1]

        dp[i] = 2 * dp[i - 1]

        if current_char in last_occurrence:
            prev_index = last_occurrence[current_char]
            dp[i] = dp[i] - dp[prev_index - 1]

        last_occurrence[current_char] = i

    return dp[n]
